import { GithubRelease } from "../types";

const GITHUB_API_BASE = "https://api.github.com/repos";

export const checkUpdate = async (repoOwner: string, repoName: string): Promise<GithubRelease | null> => {
  try {
    const response = await fetch(`${GITHUB_API_BASE}/${repoOwner}/${repoName}/releases/latest`);
    if (!response.ok) {
      throw new Error("Failed to fetch release info");
    }
    const data = await response.json();
    return {
      tag_name: data.tag_name,
      html_url: data.html_url,
    };
  } catch (error) {
    console.error(`Error checking update for ${repoName}:`, error);
    return null;
  }
};

import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';
import { Terminal, Trash2 } from 'lucide-react';

interface ConsoleLogProps {
  logs: LogEntry[];
  onClear: () => void;
}

export const ConsoleLog: React.FC<ConsoleLogProps> = ({ logs, onClear }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  return (
    <div className="flex flex-col h-full bg-slate-900 border-t border-slate-700">
      <div className="flex items-center justify-between px-4 py-2 bg-slate-850 border-b border-slate-800">
        <div className="flex items-center gap-2 text-slate-400 text-sm font-semibold uppercase tracking-wider">
          <Terminal size={14} />
          <span>Output Console</span>
        </div>
        <button 
          onClick={onClear}
          className="p-1 hover:bg-slate-700 rounded text-slate-400 hover:text-red-400 transition-colors"
          title="Clear Console"
        >
          <Trash2 size={14} />
        </button>
      </div>
      <div className="flex-1 overflow-y-auto p-4 font-mono text-xs space-y-1">
        {logs.length === 0 && (
          <div className="text-slate-600 italic">Ready. Waiting for commands...</div>
        )}
        {logs.map((log) => (
          <div key={log.id} className="break-all whitespace-pre-wrap">
            <span className="text-slate-500 mr-2">[{log.timestamp}]</span>
            <span className={
              log.type === 'error' ? 'text-red-400 font-bold' :
              log.type === 'success' ? 'text-green-400 font-bold' :
              log.type === 'command' ? 'text-blue-400' :
              'text-slate-300'
            }>
              {log.type === 'command' ? '$ ' : ''}{log.message}
            </span>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>
    </div>
  );
};

import React from 'react';
