  activeProfileId,
  onSelectProfile,
  onUpdateProfile,
  onAddProfile,
  onDeleteProfile,
}) => {
  const activeProfile = profiles.find((p) => p.id === activeProfileId);

  const handleChange = (field: keyof GameProfile, value: string) => {
    if (activeProfile) {
      onUpdateProfile({ ...activeProfile, [field]: value });
    }
