        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1">Paks Folder Path</label>
          <div className="flex gap-2">
            <input
              type="text"
              value={activeProfile.paksPath}
              onChange={(e) => handleChange('paksPath', e.target.value)}
