import React, { useState } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, ArrowRight, Play, AlertCircle } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand }) => {
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.RETOC);
  const [filterPath, setFilterPath] = useState('');
  const [modSource, setModSource] = useState('');
  const [outputModName, setOutputModName] = useState(`z_${activeProfile.name.replace(/\s+/g, '')}_Mod_P`);

  const handleExtract = () => {
    if (!filterPath) {
        onRunCommand("Error: Filter path is empty", "Validation Error");
        return;
    }

    let cmd = "";
    if (activeTool === ToolType.RETOC) {
      cmd = `"${settings.retocPath}" to-legacy --filter "${filterPath}" "${activeProfile.paksPath}" "Output/Extracted"`;
      if (activeProfile.aesKey) cmd += ` --aes "${activeProfile.aesKey}"`;
    } else {
      cmd = `"${settings.castocPath}" extract "${activeProfile.paksPath}" --filter "${filterPath}"`;
    }
    onRunCommand(cmd, `Extracting with ${activeTool}`);
  };

  const handlePack = () => {
    if (!modSource || !outputModName) {
        onRunCommand("Error: Source path or output name is empty", "Validation Error");
        return;
    }

    let cmd = "";
    if (activeTool === ToolType.RETOC) {
      cmd = `"${settings.retocPath}" to-zen --version ${activeProfile.engineVersion} "${modSource}" "${outputModName}.utoc"`;
    } else {
      cmd = `"${settings.castocPath}" pack "${modSource}" -o "${outputModName}" -v ${activeProfile.engineVersion}`;
    }
    onRunCommand(cmd, `Packing Mod with ${activeTool}`);
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Tool Selection Header */}
      <div className="bg-slate-900 border-b border-slate-800 p-4 flex justify-center gap-6">
        <label className={`cursor-pointer flex items-center gap-3 px-6 py-3 rounded-xl border transition-all ${activeTool === ToolType.RETOC ? 'bg-blue-900/20 border-blue-500 text-blue-400' : 'border-slate-700 text-slate-500 hover:border-slate-600'}`}>
          <input 
            type="radio" 
            name="tool" 
            className="hidden" 
            checked={activeTool === ToolType.RETOC} 
            onChange={() => setActiveTool(ToolType.RETOC)} 
          />
          <div className="font-bold">Use Retoc</div>
          <div className="text-xs opacity-70">Legacy Support</div>
        </label>

        <label className={`cursor-pointer flex items-center gap-3 px-6 py-3 rounded-xl border transition-all ${activeTool === ToolType.CASTOC ? 'bg-purple-900/20 border-purple-500 text-purple-400' : 'border-slate-700 text-slate-500 hover:border-slate-600'}`}>
          <input 
            type="radio" 
            name="tool" 
            className="hidden" 
            checked={activeTool === ToolType.CASTOC} 
            onChange={() => setActiveTool(ToolType.CASTOC)} 
          />
          <div className="font-bold">Use Castoc</div>
          <div className="text-xs opacity-70">Modern / Experimental</div>
        </label>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extraction (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Extract assets for editing</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Internal Filter Path</label>
                <div className="relative">
                    <input
                    type="text"
                    value={filterPath}
                    onChange={(e) => setFilterPath(e.target.value)}
                    placeholder="e.g. GameName/Content/Characters/..."
                    className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-10"
                    />
                    <div className="absolute left-3 top-3 text-slate-600">/</div>
                </div>
                <p className="text-xs text-slate-600 mt-2 flex items-center gap-1">
                    <AlertCircle size={10} />
                    Using Paks from: <span className="font-mono text-slate-500 truncate max-w-[200px]">{activeProfile.paksPath}</span>
                </p>
              </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                onClick={handleExtract}
                className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
              >
                <Play size={18} fill="currentColor" /> EXTRACT SELECTED
              </button>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Packing (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Repack your mod for distribution</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Mod Source Folder</label>
                <input
                  type="text"
                  value={modSource}
                  onChange={(e) => setModSource(e.target.value)}
                  placeholder="Path to folder containing .uasset/.uexp"
                  className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Output Mod Name</label>
                <div className="flex items-center">
                    <input
                    type="text"
                    value={outputModName}
                    onChange={(e) => setOutputModName(e.target.value)}
                    className="w-full bg-slate-950 border border-slate-700 rounded-l p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm"
                    />
                    <div className="bg-slate-800 border border-l-0 border-slate-700 p-3 rounded-r text-slate-500 font-mono text-sm">
                        .utoc
                    </div>
                </div>
              </div>

               <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500">
                  Targeting Engine: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span>
               </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                 onClick={handlePack}
                 className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
              >
                <Play size={18} fill="currentColor" /> PACK MOD
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppSettings, GithubRelease } from '../types';
import { checkUpdate } from '../services/githubService';
import { Download, RefreshCw, CheckCircle, XCircle, Github } from 'lucide-react';

interface SettingsTabProps {
  settings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
}

export const SettingsTab: React.FC<SettingsTabProps> = ({ settings, onUpdateSettings }) => {
  const [retocRelease, setRetocRelease] = useState<GithubRelease | null>(null);
  const [guiRelease, setGuiRelease] = useState<GithubRelease | null>(null);
  const [loading, setLoading] = useState(false);

  const handleCheckUpdates = async () => {
    setLoading(true);
    const rRelease = await checkUpdate("trumank", "retoc");
    const gRelease = await checkUpdate("atenfyr", "UAssetGUI");
    setRetocRelease(rRelease);
    setGuiRelease(gRelease);
    setLoading(false);
  };

  useEffect(() => {
    handleCheckUpdates();
  }, []);

  return (
    <div className="p-6 max-w-4xl mx-auto space-y-8 animate-fadeIn">

      {/* Tool Paths */}
      <section className="space-y-4">
        <h3 className="text-lg font-bold text-white border-b border-slate-800 pb-2">Tool Configuration</h3>

        <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Retoc Executable Path</label>
            <input
                type="text"
                value={settings.retocPath}
                onChange={(e) => onUpdateSettings({...settings, retocPath: e.target.value})}
                className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none font-mono text-sm"
            />
        </div>

        <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Castoc Executable Path</label>
            <input
                type="text"
                value={settings.castocPath}
                onChange={(e) => onUpdateSettings({...settings, castocPath: e.target.value})}
                className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none font-mono text-sm"
            />
        </div>
      </section>

      {/* Update Checker */}
      <section className="space-y-4">
        <div className="flex justify-between items-center border-b border-slate-800 pb-2">
            <h3 className="text-lg font-bold text-white">Update Checker</h3>
            <button 
                onClick={handleCheckUpdates}
                disabled={loading}
                className="text-sm bg-slate-800 hover:bg-slate-700 text-blue-400 px-3 py-1.5 rounded flex items-center gap-2 transition-colors disabled:opacity-50"
            >
                <RefreshCw size={14} className={loading ? "animate-spin" : ""} /> Check Now
            </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Retoc Card */}
            <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 flex justify-between items-start">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Github size={16} />
                        <span className="font-bold text-slate-200">trumank/retoc</span>
                    </div>
                    {retocRelease ? (
                         <div className="text-sm text-green-400 flex items-center gap-1">
                            <CheckCircle size={12} /> Latest: {retocRelease.tag_name}
                         </div>
                    ) : (
                        <div className="text-sm text-slate-500">Checking...</div>
                    )}
                </div>
                {retocRelease && (
                    <a href={retocRelease.html_url} target="_blank" rel="noreferrer" className="bg-slate-800 hover:bg-slate-700 p-2 rounded text-slate-300">
                        <Download size={18} />
                    </a>
                )}
            </div>

             {/* UAssetGUI Card */}
             <div className="bg-slate-900 border border-slate-800 rounded-lg p-4 flex justify-between items-start">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Github size={16} />
                        <span className="font-bold text-slate-200">atenfyr/UAssetGUI</span>
                    </div>
                    {guiRelease ? (
                         <div className="text-sm text-green-400 flex items-center gap-1">
                            <CheckCircle size={12} /> Latest: {guiRelease.tag_name}
                         </div>
                    ) : (
                        <div className="text-sm text-slate-500">Checking...</div>
                    )}
                </div>
                {guiRelease && (
                    <a href={guiRelease.html_url} target="_blank" rel="noreferrer" className="bg-slate-800 hover:bg-slate-700 p-2 rounded text-slate-300">
                        <Download size={18} />
                    </a>
                )}
            </div>
        </div>
      </section>

      <div className="bg-blue-900/10 border border-blue-900/50 p-4 rounded text-xs text-blue-200">
        <strong className="block mb-1">Note for Web Version:</strong>
        This is a browser-based prototype. Actual binary execution logic (running .exe files) requires this interface to be hosted within an Electron, Tauri, or Python native wrapper.
      </div>

    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameProfile, AppSettings, LogEntry, EngineVersion } from './types';
import { DEFAULT_PROFILE, DEFAULT_SETTINGS, MOCK_PROFILES } from './constants';
import { ProfileTab } from './components/ProfileTab';
import { OperationsTab } from './components/OperationsTab';
import { SettingsTab } from './components/SettingsTab';
import { ConsoleLog } from './components/ConsoleLog';
import { Gamepad2, Settings, Wrench, Boxes } from 'lucide-react';

const TABS = [
  { id: 'profiles', label: 'Game Profiles', icon: Gamepad2 },
  { id: 'ops', label: 'Operations', icon: Wrench },
  { id: 'settings', label: 'Settings', icon: Settings },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('profiles');
  const [profiles, setProfiles] = useState<GameProfile[]>(MOCK_PROFILES);
  const [activeProfileId, setActiveProfileId] = useState<string>(MOCK_PROFILES[0].id);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Helper to find the active profile object
  const activeProfile = profiles.find(p => p.id === activeProfileId) || profiles[0];

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    const newLog: LogEntry = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    };
    setLogs(prev => [...prev, newLog]);
  }, []);

  // --- Profile Actions ---
  const handleAddProfile = () => {
    const newId = Math.random().toString(36).substr(2, 5);
    const newProfile = { ...DEFAULT_PROFILE, id: newId, name: `New Game ${newId}` };
    setProfiles([...profiles, newProfile]);
    setActiveProfileId(newId);
    addLog(`Created new profile: ${newProfile.name}`, 'success');
  };

  const handleDeleteProfile = (id: string) => {
    if (profiles.length <= 1) return;
    const newProfiles = profiles.filter(p => p.id !== id);
    setProfiles(newProfiles);
    setActiveProfileId(newProfiles[0].id);
    addLog(`Deleted profile ID: ${id}`, 'info');
  };

  const handleUpdateProfile = (updated: GameProfile) => {
    setProfiles(profiles.map(p => p.id === updated.id ? updated : p));
  };

  // --- Command Execution Simulation ---
  const handleRunCommand = (cmd: string, description: string) => {
    if (cmd.startsWith("Error")) {
        addLog(cmd, 'error');
        return;
    }

    addLog(`Starting: ${description}...`, 'info');
    addLog(cmd, 'command');

    // Simulate async process
    setTimeout(() => {
        addLog("Initializing Unreal Zen Storage...", 'info');
    }, 500);

    setTimeout(() => {
        if (Math.random() > 0.9) {
             addLog("Error: Magic mismatch in container header. Check Engine Version.", 'error');
        } else {
             addLog(`Process completed successfully.`, 'success');
        }
    }, 2500);
  };

  return (
    <div className="flex h-screen w-full">
      {/* Sidebar / Main Content Wrapper */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Top Navigation */}
        <header className="bg-slate-900 border-b border-slate-800 h-16 flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="bg-blue-600 p-1.5 rounded-lg shadow-lg shadow-blue-500/20">
                <Boxes className="text-white" size={20} />
             </div>
             <h1 className="text-xl font-bold tracking-tight text-white hidden sm:block">Universal <span className="text-blue-500">UE5 Zen</span> Tool</h1>
          </div>

          <nav className="flex gap-1 bg-slate-800/50 p-1 rounded-lg">
            {TABS.map(tab => {
              const Icon = tab.icon;
              const isActive = activeTab === tab.id;
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${
                    isActive 
                      ? 'bg-slate-700 text-white shadow-sm' 
                      : 'text-slate-400 hover:text-white hover:bg-slate-800'
                  }`}
                >
                  <Icon size={16} />
                  {tab.label}
                </button>
              );
            })}
          </nav>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto bg-slate-950 relative">
          <div className="h-full">
            {activeTab === 'profiles' && (
              <ProfileTab 
                profiles={profiles}
                activeProfileId={activeProfileId}
                onSelectProfile={setActiveProfileId}
                onUpdateProfile={handleUpdateProfile}
                onAddProfile={handleAddProfile}
                onDeleteProfile={handleDeleteProfile}
              />
            )}
            {activeTab === 'ops' && (
              <OperationsTab 
                activeProfile={activeProfile}
                settings={settings}
                onRunCommand={handleRunCommand}
              />
            )}
            {activeTab === 'settings' && (
              <SettingsTab 
                settings={settings}
                onUpdateSettings={setSettings}
              />
            )}
          </div>
        </main>

        {/* Bottom Console */}
        <div className="h-48 shrink-0">
          <ConsoleLog logs={logs} onClear={() => setLogs([])} />
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, ArrowRight, Play, AlertCircle, FolderOpen } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand }) => {
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.RETOC);
  const [filterPath, setFilterPath] = useState('');
  const [extractOutputPath, setExtractOutputPath] = useState('D:\\Modding\\Extracted');
  const [modSource, setModSource] = useState('');
  const [outputModName, setOutputModName] = useState(`z_${activeProfile.name.replace(/\s+/g, '')}_Mod_P`);

  const handleExtract = () => {
    if (!filterPath) {
        onRunCommand("Error: Filter path is empty", "Validation Error");
        return;
    }
    if (!extractOutputPath) {
        onRunCommand("Error: Extraction Output path is empty", "Validation Error");
        return;
    }

    let cmd = "";
    if (activeTool === ToolType.RETOC) {
      // retoc.exe to-legacy --filter "FilterPath" "PaksPath" "OutputPath"
      cmd = `"${settings.retocPath}" to-legacy --filter "${filterPath}" "${activeProfile.paksPath}" "${extractOutputPath}"`;
      if (activeProfile.aesKey) cmd += ` --aes "${activeProfile.aesKey}"`;
    } else {
      // Castoc syntax assumptions: castoc extract "ContainerPath" "OutputPath" --filter "Filter"
      cmd = `"${settings.castocPath}" extract "${activeProfile.paksPath}" "${extractOutputPath}" --filter "${filterPath}"`;
    }
    onRunCommand(cmd, `Extracting with ${activeTool}`);
  };

  const handlePack = () => {
    if (!modSource || !outputModName) {
        onRunCommand("Error: Source path or output name is empty", "Validation Error");
        return;
    }

    let cmd = "";
    if (activeTool === ToolType.RETOC) {
      cmd = `"${settings.retocPath}" to-zen --version ${activeProfile.engineVersion} "${modSource}" "${outputModName}.utoc"`;
    } else {
      cmd = `"${settings.castocPath}" pack "${modSource}" -o "${outputModName}" -v ${activeProfile.engineVersion}`;
    }
    onRunCommand(cmd, `Packing Mod with ${activeTool}`);
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Tool Selection Header */}
      <div className="bg-slate-900 border-b border-slate-800 p-4 flex justify-center gap-6">
        <label className={`cursor-pointer flex items-center gap-3 px-6 py-3 rounded-xl border transition-all ${activeTool === ToolType.RETOC ? 'bg-blue-900/20 border-blue-500 text-blue-400' : 'border-slate-700 text-slate-500 hover:border-slate-600'}`}>
          <input 
            type="radio" 
            name="tool" 
            className="hidden" 
            checked={activeTool === ToolType.RETOC} 
            onChange={() => setActiveTool(ToolType.RETOC)} 
          />
          <div className="font-bold">Use Retoc</div>
          <div className="text-xs opacity-70">Legacy Support</div>
        </label>

        <label className={`cursor-pointer flex items-center gap-3 px-6 py-3 rounded-xl border transition-all ${activeTool === ToolType.CASTOC ? 'bg-purple-900/20 border-purple-500 text-purple-400' : 'border-slate-700 text-slate-500 hover:border-slate-600'}`}>
          <input 
            type="radio" 
            name="tool" 
            className="hidden" 
            checked={activeTool === ToolType.CASTOC} 
            onChange={() => setActiveTool(ToolType.CASTOC)} 
          />
          <div className="font-bold">Use Castoc</div>
          <div className="text-xs opacity-70">Modern / Experimental</div>
        </label>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extraction (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Extract assets for editing</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Internal Filter Path (Full .uasset path)</label>
                <div className="relative">
                    <input
                    type="text"
                    value={filterPath}
                    onChange={(e) => setFilterPath(e.target.value)}
                    placeholder="/GameName/Content/Path/To/Asset.uasset"
                    className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8"
                    />
                    <div className="absolute left-3 top-3 text-slate-600">/</div>
                </div>
                <p className="text-xs text-slate-500 mt-2">
                   Must point to a specific file (e.g. .uasset), not a folder.
                </p>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Output Extraction Folder</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={extractOutputPath}
                    onChange={(e) => setExtractOutputPath(e.target.value)}
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm"
                    />
                     <button className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400" title="Browse">
                        <FolderOpen size={18} />
                     </button>
                </div>
              </div>

              <div className="p-3 bg-slate-950/50 rounded border border-slate-800 text-xs space-y-1">
                 <div className="text-slate-500 flex items-center gap-2">
                    <AlertCircle size={10} />
                    <span>Reading Paks from Profile:</span>
                 </div>
                 <div className="font-mono text-slate-400 break-all pl-4 border-l-2 border-slate-800">
                    {activeProfile.paksPath}
                 </div>
              </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                onClick={handleExtract}
                className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
              >
                <Play size={18} fill="currentColor" /> EXTRACT SELECTED
              </button>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Packing (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Repack your mod for distribution</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Mod Source Folder</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={modSource}
                    onChange={(e) => setModSource(e.target.value)}
                    placeholder="Path to folder containing .uasset/.uexp"
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm"
                    />
                     <button className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400" title="Browse">
                        <FolderOpen size={18} />
                     </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Output Mod Name</label>
                <div className="flex items-center">
                    <input
                    type="text"
                    value={outputModName}
                    onChange={(e) => setOutputModName(e.target.value)}
                    className="w-full bg-slate-950 border border-slate-700 rounded-l p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm"
                    />
                    <div className="bg-slate-800 border border-l-0 border-slate-700 p-3 rounded-r text-slate-500 font-mono text-sm">
                        .utoc
                    </div>
                </div>
              </div>

               <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500">
                  Targeting Engine: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span>
               </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                 onClick={handlePack}
                 className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
              >
                <Play size={18} fill="currentColor" /> PACK MOD
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

