import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';
import { Terminal, Trash2 } from 'lucide-react';

interface ConsoleLogProps {
  logs: LogEntry[];
  onClear: () => void;
}

export const ConsoleLog: React.FC<ConsoleLogProps> = ({ logs, onClear }) => {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  return (
    <div className="flex flex-col h-full bg-slate-900 border-t border-slate-700">
      <div className="flex items-center justify-between px-4 py-2 bg-slate-850 border-b border-slate-800">
        <div className="flex items-center gap-2 text-slate-400 text-sm font-semibold uppercase tracking-wider">
          <Terminal size={14} />
          <span>Výstupná Konzola (Log)</span>
        </div>
        <button 
          onClick={onClear}
          className="p-1 hover:bg-slate-700 rounded text-slate-400 hover:text-red-400 transition-colors"
          title="Vymazať konzolu"
        >
          <Trash2 size={14} />
        </button>
      </div>
      <div className="flex-1 overflow-y-auto p-4 font-mono text-xs space-y-1">
        {logs.length === 0 && (
          <div className="text-slate-600 italic">Pripravený. Čakám na príkazy...</div>
        )}
        {logs.map((log) => (
          <div key={log.id} className="break-all whitespace-pre-wrap">
            <span className="text-slate-500 mr-2">[{log.timestamp}]</span>
            <span className={
              log.type === 'error' ? 'text-red-400 font-bold' :
              log.type === 'success' ? 'text-green-400 font-bold' :
              log.type === 'command' ? 'text-blue-400' :
              'text-slate-300'
            }>
              {log.type === 'command' ? '$ ' : ''}{log.message}
            </span>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>
    </div>
  );
};

import React from 'react';
import { GameProfile, EngineVersion } from '../types';
import { Save, Trash, Plus, FolderOpen, HelpCircle } from 'lucide-react';

interface ProfileTabProps {
  profiles: GameProfile[];
  activeProfileId: string;
  onSelectProfile: (id: string) => void;
  onUpdateProfile: (profile: GameProfile) => void;
  onAddProfile: () => void;
  onDeleteProfile: (id: string) => void;
}

export const ProfileTab: React.FC<ProfileTabProps> = ({
  profiles,
  activeProfileId,
  onSelectProfile,
  onUpdateProfile,
  onAddProfile,
  onDeleteProfile,
}) => {
  const activeProfile = profiles.find((p) => p.id === activeProfileId);

  const handleChange = (field: keyof GameProfile, value: string) => {
    if (activeProfile) {
      onUpdateProfile({ ...activeProfile, [field]: value });
    }
  };

  if (!activeProfile) return <div className="p-8 text-center text-slate-500">Žiadne profily neboli načítané.</div>;

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto animate-fadeIn">
      {/* Header / Selector */}
      <div className="flex items-end gap-4 border-b border-slate-800 pb-6">
        <div className="flex-1">
          <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Aktuálny Profil Hry</label>
          <div className="relative">
            <select
              value={activeProfileId}
              onChange={(e) => onSelectProfile(e.target.value)}
              className="w-full bg-slate-900 text-white border border-slate-700 rounded-lg p-3 pr-10 appearance-none focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
            >
              {profiles.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name}
                </option>
              ))}
            </select>
            <div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-400">
              <svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>
            </div>
          </div>
          <p className="text-xs text-slate-500 mt-1">Vyberte hru, ktorú chcete modovať.</p>
        </div>
        <button
          onClick={onAddProfile}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-3 rounded-lg flex items-center gap-2 font-medium transition-colors"
          title="Pridať novú hru"
        >
          <Plus size={18} /> Nová Hra
