  useEffect(() => {
    handleCheckUpdates();
  }, []);

  const handleBrowse = (field: keyof AppSettings) => {
    setActiveField(field);
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeField) {
        // V Electron prostredí by file.path obsahoval plnú cestu.
        // Vo webe to simulujeme.
        // @ts-ignore
        const fullPath = file.path || `C:\\Tools\\Selected\\${file.name}`;
        onUpdateSettings({ ...settings, [activeField]: fullPath });
