    // Spustenie príkazu
    batContent += `echo [2/2] Spúšťam balenie...\n`;
    let runCmd = "";
    if (activeTool === ToolType.RETOC) {
        // retoc syntax: to-zen --version VER INPUT OUTPUT
        // Používame "%~dp0retoc.exe" pre spustenie skopírovaného nástroja v aktuálnom priečinku
        runCmd = `"%~dp0${toolName}" to-zen --version ${activeProfile.engineVersion} "${modSource}" "${outputModName}.utoc"`;
    } else {
        runCmd = `"%~dp0${toolName}" pack "${modSource}" -o "${outputModName}" -v ${activeProfile.engineVersion}`;
    }
    batContent += `${runCmd}\n\n`;

    batContent += "if %errorlevel% neq 0 ( color 4f & echo [FAILED] Chyba pri balení. ) else ( color 2f & echo [SUCCESS] Hotovo! Súbory vytvorené. )\n";
    batContent += "pause\n";

    // 2. Stiahnutie súboru (Web spôsob)
    // V desktop aplikácii (Electron) by sme použili fs.writeFileSync
    const blob = new Blob([batContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `RUN_PACK_${outputModName}.bat`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // 3. Logovanie
    onRunCommand(
        `Generujem skript pre: ${toolPath}\nPríkaz: ${runCmd}`, 
        `Vytvorený .bat súbor a pripravené kopírovanie`
    );
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs */}
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept=".uasset" 
