      />
      <input 
        type="file" 
        ref={folderInputRef} 
        className="hidden" 
        {...({ webkitdirectory: "", directory: "" } as any)}
        onChange={handleFolderChange} 
      />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Rozbalenie súborov hry na úpravu</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                <div className="relative">
                    <input
                    type="text"
                    value={filterPath}
                    onChange={(e) => setFilterPath(e.target.value)}
                    placeholder="/GameName/Content/Path/To/Asset.uasset"
                    className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                    />
                    <div className="absolute left-3 top-3 text-slate-600">/</div>
                </div>
                {/* File picker for filter (simulates selecting a file inside the container, technically incorrect for retoc but good UX for finding the name) */}
                <div className="text-right mt-1">
                    <button onClick={handleBrowseFile} className="text-xs text-blue-400 hover:text-blue-300 underline">
                        Vybrať súbor na disku (pre názov)
                    </button>
                </div>

                <div className="text-xs text-slate-500 mt-2 space-y-2">
                   <p className="flex gap-1"><Info size={12} className="mt-0.5 shrink-0" /> <span>Musí to byť <strong>celá interná cesta</strong> k súboru, nie k priečinku.</span></p>
                   <p className="pl-4">Príklad: <code>/Augusta/Content/Items/Sword.uasset</code></p>
                   <p className="flex items-center gap-1 pl-4 pt-1 text-slate-400 border-t border-slate-800/50 mt-2">
                      <span>Tip: Správnu cestu zistíte cez program</span>
                      <a 
                        href="https://fmodel.app/" 
                        target="_blank" 
                        rel="noreferrer" 
                        className="text-blue-400 hover:text-blue-300 underline flex items-center gap-0.5"
                      >
                        Fmodel <ExternalLink size={10} />
                      </a>
                   </p>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={extractOutputPath}
                    onChange={(e) => setExtractOutputPath(e.target.value)}
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder('extract')}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors" 
                        title="Prehľadávať"
                     >
                        <FolderOpen size={18} />
                     </button>
                </div>
                <p className="text-xs text-slate-500 mt-1">
                  Sem sa uložia použiteľné súbory (.uasset, .uexp), ktoré môžete editovať v Unreal Engine.
                </p>
              </div>

              <div className="p-3 bg-slate-950/50 rounded border border-slate-800 text-xs space-y-1">
                 <div className="text-slate-500 flex items-center gap-2">
                    <AlertCircle size={10} />
