  const handlePack = () => {
    if (!modSource || !outputModName) {
        onRunCommand("Chyba: Zdrojový priečinok alebo názov módu je prázdny", "Chyba Validácie");
        return;
    }

    // 1. Zostavenie obsahu .ps1 súboru (PowerShell)
    let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
    let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;

    // PowerShell Script Header
    let psContent = "# Universal UE5 Zen Tool - Auto Packer Script\n";
    psContent += "$Host.UI.RawUI.WindowTitle = 'Universal UE5 Zen Tool - Auto Packer'\n";
    psContent += "Write-Host '==========================================' -ForegroundColor Cyan\n";
    psContent += `Write-Host '      Auto-Packing: ${outputModName}' -ForegroundColor Cyan\n`;
    psContent += "Write-Host '==========================================' -ForegroundColor Cyan\n\n";

    // Define Paths
    // Note: Use single quotes for paths in PS to avoid variable expansion, but interpolate JS variables.
    psContent += `# Configuration\n`;
    psContent += `$ToolSource = '${toolPath}'\n`;
    psContent += `$ToolName = '${toolName}'\n`;
    psContent += `$CurrentDir = $PSScriptRoot\n`;
    psContent += `$ToolDest = Join-Path -Path $CurrentDir -ChildPath $ToolName\n\n`;

    // Copy Tool logic
    psContent += `Write-Host "[1/2] Kopírujem $ToolName do aktuálneho priečinka..." -ForegroundColor Yellow\n`;
    psContent += "try {\n";
    psContent += "    Copy-Item -Path $ToolSource -Destination $ToolDest -Force -ErrorAction Stop\n";
    psContent += "} catch {\n";
    psContent += "    Write-Host '[ERROR] Nepodarilo sa skopírovať nástroj.' -ForegroundColor Red\n";
    psContent += "    Write-Host $_.Exception.Message -ForegroundColor Red\n";
    psContent += "    Read-Host 'Stlačte Enter pre ukončenie...'\n";
    psContent += "    exit\n";
    psContent += "}\n\n";

    // Run Command logic
    psContent += `Write-Host "[2/2] Spúšťam balenie..." -ForegroundColor Yellow\n`;

    if (activeTool === ToolType.RETOC) {
        // Syntax: retoc.exe to-zen --version VER INPUT OUTPUT
        // Note: Using & operator to execute command
        psContent += `& $ToolDest to-zen --version ${activeProfile.engineVersion} "${modSource}" "${outputModName}.utoc"\n`;
    } else {
        // Syntax: castoc.exe pack INPUT -o OUTPUT -v VER
        psContent += `& $ToolDest pack "${modSource}" -o "${outputModName}" -v ${activeProfile.engineVersion}\n`;
    }

    psContent += "\nif ($LASTEXITCODE -eq 0) {\n";
    psContent += "    Write-Host '[SUCCESS] Hotovo! Súbory vytvorené.' -ForegroundColor Green\n";
    psContent += "} else {\n";
    psContent += "    Write-Host \"[FAILED] Chyba pri balení (Exit Code: $LASTEXITCODE).\" -ForegroundColor Red\n";
    psContent += "}\n\n";
    psContent += "Read-Host 'Stlačte Enter pre ukončenie...'\n";

    // 2. Stiahnutie súboru (Web spôsob)
    // V desktop aplikácii (Electron) by sme použili fs.writeFileSync
    const blob = new Blob([psContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `RUN_PACK_${outputModName}.ps1`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // 3. Logovanie
    onRunCommand(
        `Generujem PowerShell skript pre: ${toolPath}\nTyp: ${activeTool}`, 
        `Vytvorený .ps1 súbor a pripravené kopírovanie`
    );
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs */}
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept=".uasset" 
        onChange={handleFileChange} 
      />
      <input 
        type="file" 
        ref={folderInputRef} 
        className="hidden" 
        {...({ webkitdirectory: "", directory: "" } as any)}
        onChange={handleFolderChange} 
      />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Rozbalenie súborov hry na úpravu</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                <div className="relative">
                    <input
                    type="text"
                    value={filterPath}
                    onChange={(e) => setFilterPath(e.target.value)}
                    placeholder="/GameName/Content/Path/To/Asset.uasset"
                    className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                    />
                    <div className="absolute left-3 top-3 text-slate-600">/</div>
                </div>
                {/* File picker for filter (simulates selecting a file inside the container, technically incorrect for retoc but good UX for finding the name) */}
                <div className="text-right mt-1">
                    <button onClick={handleBrowseFile} className="text-xs text-blue-400 hover:text-blue-300 underline">
                        Vybrať súbor na disku (pre názov)
                    </button>
                </div>

                <div className="text-xs text-slate-500 mt-2 space-y-2">
                   <p className="flex gap-1"><Info size={12} className="mt-0.5 shrink-0" /> <span>Musí to byť <strong>celá interná cesta</strong> k súboru, nie k priečinku.</span></p>
                   <p className="pl-4">Príklad: <code>/Augusta/Content/Items/Sword.uasset</code></p>
                   <p className="flex items-center gap-1 pl-4 pt-1 text-slate-400 border-t border-slate-800/50 mt-2">
                      <span>Tip: Správnu cestu zistíte cez program</span>
                      <a 
                        href="https://fmodel.app/" 
                        target="_blank" 
                        rel="noreferrer" 
                        className="text-blue-400 hover:text-blue-300 underline flex items-center gap-0.5"
                      >
                        Fmodel <ExternalLink size={10} />
                      </a>
                   </p>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={extractOutputPath}
                    onChange={(e) => setExtractOutputPath(e.target.value)}
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder('extract')}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors" 
                        title="Prehľadávať"
                     >
                        <FolderOpen size={18} />
                     </button>
                </div>
                <p className="text-xs text-slate-500 mt-1">
                  Sem sa uložia použiteľné súbory (.uasset, .uexp), ktoré môžete editovať v Unreal Engine.
                </p>
              </div>

              <div className="p-3 bg-slate-950/50 rounded border border-slate-800 text-xs space-y-1">
                 <div className="text-slate-500 flex items-center gap-2">
                    <AlertCircle size={10} />
                    <span>Čítam .pak súbory z profilu:</span>
                 </div>
                 <div className="font-mono text-slate-400 break-all pl-4 border-l-2 border-slate-800">
                    {activeProfile.paksPath}
                 </div>
              </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                onClick={handleExtract}
                className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
              >
                <Play size={18} fill="currentColor" /> EXTRAHOVAŤ VYBRANÉ
              </button>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Balenie (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Zabalenie módu pre distribúciu</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Zdrojový priečinok módu (Source)</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={modSource}
                    onChange={(e) => setModSource(e.target.value)}
                    placeholder="Napr. C:\Mods\MyMod_1_P"
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder('source')}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors" 
                        title="Prehľadávať"
                     >
                        <FolderOpen size={18} />
                     </button>
                </div>
                <div className="text-xs text-slate-500 mt-2 space-y-1">
                    <p>Tento priečinok musí obsahovať štruktúru <code>/Content/...</code> s vašimi upravenými súbormi.</p>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Názov výstupného súboru (Mod Name)</label>
                <div className="flex items-center">
                    <input
                    type="text"
                    value={outputModName}
                    onChange={(e) => setOutputModName(e.target.value)}
                    className="w-full bg-slate-950 border border-slate-700 rounded-l p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                    <div className="bg-slate-800 border border-l-0 border-slate-700 p-3 rounded-r text-slate-500 font-mono text-sm">
                        .utoc
                    </div>
                </div>
                <div className="bg-emerald-900/10 border border-emerald-900/30 p-2 rounded mt-2">
                    <p className="text-xs text-slate-400 flex items-start gap-1">
                    <AlertCircle size={12} className="mt-0.5 text-emerald-500 shrink-0"/>
                    <span>
                        <strong>Pravidlá pomenovania:</strong> <code>Nazov_#_P</code> (napr. <em>MyMod_1_P</em>). 
                        <br/>Číslo (1-999) je kritické. Hra načíta vyššie číslo ako "patch" nad originálnymi súbormi. Bez čísla mód nemusí fungovať.
                    </span>
                    </p>
                </div>
              </div>

               <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500 flex justify-between items-center">
                  <span>Aktívny nástroj: <span className={activeTool === ToolType.RETOC ? "text-blue-400 font-bold" : "text-purple-400 font-bold"}>{activeTool}</span></span>
                  <span>Cieľová Verzia: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span></span>
               </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800">
              <button 
                 onClick={handlePack}
                 className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
                 title="Vygeneruje .ps1 súbor a skopíruje nástroj do priečinka"
              >
                <div className="flex items-center gap-2">
                    <FileText size={18} fill="currentColor" /> 
                    <span>VYTVORIŤ .PS1 & ZABALIŤ</span>
                </div>
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, ArrowRight, Play, AlertCircle, FolderOpen, Info, ExternalLink, FileText, Download } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
  activeTool: ToolType;
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand, activeTool }) => {
  // Extraction States
  const [filterPath, setFilterPath] = useState('');
  const [extractOutputPath, setExtractOutputPath] = useState('D:\\Modding\\Extracted');

  // Packing States
  const [modSource, setModSource] = useState('');
  const [packDestFolder, setPackDestFolder] = useState(''); // Kam sa uloží .utoc

  // Naming parts based on: z_Grounded2_SK_300_P
  const [modNameStr, setModNameStr] = useState('Grounded2');
  const [modChunkId, setModChunkId] = useState('300');

  // Input Refs for browsing
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeBrowseOp, setActiveBrowseOp] = useState<'filter' | 'extract' | 'source' | 'packDest' | null>(null);

  const handleBrowseFile = () => {
    setActiveBrowseOp('filter');
    fileInputRef.current?.click();
  };

  const handleBrowseFolder = (op: 'extract' | 'source' | 'packDest') => {
    setActiveBrowseOp(op);
    folderInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeBrowseOp === 'filter') {
        const mockInternalPath = `/Game/${file.name}`;
        setFilterPath(mockInternalPath);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
    setActiveBrowseOp(null);
  };

  const handleFolderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0 && activeBrowseOp) {
        // @ts-ignore
        const path = files[0].path 
             // @ts-ignore
            ? (files[0].path.includes(files[0].name) ? files[0].path.slice(0, -files[0].name.length) : files[0].path)
            : `D:\\Games\\Selected\\${files[0].webkitRelativePath.split('/')[0]}`;

        const cleanPath = path.endsWith('\\') || path.endsWith('/') ? path.slice(0, -1) : path;

        if (activeBrowseOp === 'extract') setExtractOutputPath(cleanPath);
        if (activeBrowseOp === 'source') setModSource(cleanPath);
        if (activeBrowseOp === 'packDest') setPackDestFolder(cleanPath);
    }
    if (folderInputRef.current) folderInputRef.current.value = '';
    setActiveBrowseOp(null);
  };

  const handleExtract = () => {
    if (!filterPath) {
        onRunCommand("Chyba: Cesta filtra je prázdna", "Chyba Validácie");
        return;
    }
    if (!extractOutputPath) {
        onRunCommand("Chyba: Výstupný priečinok extrakcie je prázdny", "Chyba Validácie");
        return;
    }

    let cmd = "";
    if (activeTool === ToolType.RETOC) {
      cmd = `"${settings.retocPath}" to-legacy --filter "${filterPath}" "${activeProfile.paksPath}" "${extractOutputPath}"`;
      if (activeProfile.aesKey) cmd += ` --aes "${activeProfile.aesKey}"`;
    } else {
      cmd = `"${settings.castocPath}" extract "${activeProfile.paksPath}" "${extractOutputPath}" --filter "${filterPath}"`;
    }
    onRunCommand(cmd, `Extrahujem pomocou ${activeTool}`);
  };

  const handlePack = () => {
    if (!modSource || !packDestFolder || !modNameStr) {
        onRunCommand("Chyba: Chýba zdrojový priečinok, cieľový priečinok alebo názov módu.", "Chyba Validácie");
        return;
    }

    // Zostavenie názvu súboru: z_{Meno}_SK_{ID}_P.utoc
    const finalFileName = `z_${modNameStr}_SK_${modChunkId}_P.utoc`;
    // Celá cesta k výstupnému súboru
    const fullOutputFilePath = `${packDestFolder}\\${finalFileName}`;

    let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
    let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;

    // 1. PowerShell Script Content
    let psContent = "# Universal UE5 Zen Tool - Packing Script\n";
    psContent += "$Host.UI.RawUI.WindowTitle = 'UE5 Zen Packer - " + modNameStr + "'\n";
    psContent += "Write-Host '==========================================' -ForegroundColor Cyan\n";
    psContent += `Write-Host '      Packing Mod: ${finalFileName}' -ForegroundColor Cyan\n`;
    psContent += "Write-Host '==========================================' -ForegroundColor Cyan\n\n";

    psContent += `# Config\n`;
    psContent += `$ToolPath = '${toolPath}'\n`;
    psContent += `$SourcePath = '${modSource}'\n`;
    psContent += `$DestinationFile = '${fullOutputFilePath}'\n`;
    psContent += `$Version = '${activeProfile.engineVersion}'\n\n`;

    // Validácia existencie nástroja
    psContent += "if (-not (Test-Path $ToolPath)) {\n";
    psContent += "    Write-Host \"[ERROR] Nástroj nebol nájdený na ceste: $ToolPath\" -ForegroundColor Red\n";
    psContent += "    Read-Host 'Stlačte Enter...'\n    exit\n}\n\n";

    // Spustenie príkazu (Absolute paths logic)
    // Format: & "ToolPath" to-zen --version VER "Source" "Dest"
    psContent += `Write-Host "Spúšťam ${toolName}..." -ForegroundColor Yellow\n`;
    psContent += `Write-Host "Vstup: $SourcePath" -ForegroundColor Gray\n`;
    psContent += `Write-Host "Výstup: $DestinationFile" -ForegroundColor Gray\n\n`;

    if (activeTool === ToolType.RETOC) {
        // & "F:\...\retoc.exe" to-zen --version UE5_4 "F:\...\Source" "F:\...\Output.utoc"
        psContent += `& $ToolPath to-zen --version $Version $SourcePath $DestinationFile\n`;
    } else {
        // castoc syntax fallback
        psContent += `& $ToolPath pack $SourcePath -o $DestinationFile -v $Version\n`;
    }

    psContent += "\nif ($LASTEXITCODE -eq 0) {\n";
    psContent += "    Write-Host '[SUCCESS] Mód bol úspešne zabalený!' -ForegroundColor Green\n";
    psContent += "} else {\n";
    psContent += "    Write-Host \"[FAILED] Nastala chyba (Exit Code: $LASTEXITCODE).\" -ForegroundColor Red\n";
    psContent += "}\n\n";
    psContent += "Read-Host 'Stlačte Enter pre ukončenie...'\n";

    // 2. Download .ps1
    const blob = new Blob([psContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PACK_${modNameStr}.ps1`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // 3. Log
    onRunCommand(
        `& "${toolPath}" to-zen --version ${activeProfile.engineVersion} "${modSource}" "${fullOutputFilePath}"`, 
        `Generujem skript pre ${finalFileName}`
    );
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs */}
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept=".uasset" 
        onChange={handleFileChange} 
      />
      <input 
        type="file" 
        ref={folderInputRef} 
        className="hidden" 
        {...({ webkitdirectory: "", directory: "" } as any)}
        onChange={handleFolderChange} 
      />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Rozbalenie súborov hry na úpravu</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                <div className="relative">
                    <input
                    type="text"
                    value={filterPath}
                    onChange={(e) => setFilterPath(e.target.value)}
                    placeholder="/GameName/Content/Path/To/Asset.uasset"
                    className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                    />
                    <div className="absolute left-3 top-3 text-slate-600">/</div>
                </div>
                <div className="text-right mt-1">
                    <button onClick={handleBrowseFile} className="text-xs text-blue-400 hover:text-blue-300 underline">
                        Vybrať súbor na disku (pre názov)
                    </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                <div className="flex gap-2">
                    <input
                    type="text"
                    value={extractOutputPath}
                    onChange={(e) => setExtractOutputPath(e.target.value)}
                    className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder('extract')}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors" 
                        title="Prehľadávať"
                     >
                        <FolderOpen size={18} />
                     </button>
                </div>
              </div>

              <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
                <button 
                    onClick={handleExtract}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
                >
                    <Play size={18} fill="currentColor" /> EXTRAHOVAŤ
                </button>
              </div>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Balenie (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Zabalenie módu pre distribúciu</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              {/* Source Input */}
              <div>
