    const file = e.target.files?.[0];
    if (file && activeField) {
        let newPath = "";

        // 1. Check if full path is available (Electron/Native wrapper)
        // @ts-ignore
        if (file.path) {
            // @ts-ignore
            newPath = file.path;
        } else {
            // 2. Web Environment Fallback
            // Browser security prevents reading the full path.
            // Heuristic: Try to keep the folder from the currently text-inputted path if valid.
            const currentPath = settings[activeField];
            // Basic check for windows style path
            const lastSlash = currentPath.lastIndexOf('\\');

            if (lastSlash > 0) {
                 const currentDir = currentPath.substring(0, lastSlash);
                 // If the current dir looks real (not the default placeholder), use it
                 if (currentDir && !currentDir.includes("C:\\Tools") && currentDir.length > 2) {
                     newPath = `${currentDir}\\${file.name}`;
                 } else {
                     newPath = `C:\\Path\\To\\${file.name}`;
                 }
            } else {
                 newPath = `C:\\Path\\To\\${file.name}`;
            }
        }

        onUpdateSettings({ ...settings, [activeField]: newPath });
    }

    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
    setActiveField(null);
