interface SettingsTabProps {
  settings: AppSettings;
  onUpdateSettings: (settings: AppSettings) => void;
}

export const SettingsTab: React.FC<SettingsTabProps> = ({ settings, onUpdateSettings }) => {
  const [retocRelease, setRetocRelease] = useState<GithubRelease | null>(null);
  const [guiRelease, setGuiRelease] = useState<GithubRelease | null>(null);
  const [loading, setLoading] = useState(false);

  // File Picking Logic
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [activeField, setActiveField] = useState<keyof AppSettings | null>(null);

  const handleBrowse = (field: keyof AppSettings) => {
    setActiveField(field);
    if (fileInputRef.current) {
        fileInputRef.current.value = ''; // Reset
        fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeField) {
        // @ts-ignore - file.path exists in Electron/Modern contexts
        const path = file.path || file.name;
        onUpdateSettings({ ...settings, [activeField]: path });
