import React, { useState, useRef } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, FileText, Download, FolderOpen, FileSearch } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
  activeTool: ToolType;
}

// Helper to extend HTMLInputElement attributes for React
declare module 'react' {
  interface InputHTMLAttributes<T> extends HTMLAttributes<T> {
    webkitdirectory?: string;
    directory?: string;
  }
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand, activeTool }) => {
  // Extraction States
  const [filterPath, setFilterPath] = useState('');
  const [extractOutputPath, setExtractOutputPath] = useState('D:\\Modding\\Extracted');

  // Packing States
  const [modSource, setModSource] = useState('');
  const [packDestFolder, setPackDestFolder] = useState(''); // Kam sa uloží .utoc

  // Naming parts based on: z_Grounded2_SK_300_P
  const [modNameStr, setModNameStr] = useState('Grounded2');
  const [modChunkId, setModChunkId] = useState('300');

  // --- Path Picking Logic ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeSetter, setActiveSetter] = useState<((val: string) => void) | null>(null);

  const handleBrowseFile = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
        fileInputRef.current.click();
    }
  };

  const handleBrowseFolder = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (folderInputRef.current) {
        folderInputRef.current.value = '';
        folderInputRef.current.click();
    }
  };

  const handleInputFileChange = (e: React.ChangeEvent<HTMLInputElement>, isFolder: boolean) => {
    const file = e.target.files?.[0];
    if (file && activeSetter) {
        // @ts-ignore
        let path = file.path || file.name;

        if (isFolder) {
            // Remove filename to get dir path if we used webkitdirectory but want cleaner path
            if (path.match(/\.[a-zA-Z0-9]+$/)) {
                 const lastSlash = Math.max(path.lastIndexOf('\\'), path.lastIndexOf('/'));
                 if (lastSlash !== -1) path = path.substring(0, lastSlash);
            }
        }

        activeSetter(path);
    }
    setActiveSetter(null);
  };

  const generateExtractScript = () => {
     let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
     let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;
     const assetName = filterPath.split('/').pop()?.replace('.uasset', '') || 'Asset';

     // PowerShell Script Builder
     let ps = `# Universal UE5 Zen Tool - Extraction Script\n`;
     ps += `# Generated for: ${activeProfile.name}\n\n`;

     ps += `Write-Host "Starting Extraction for: ${assetName}" -ForegroundColor Cyan\n\n`;

     // 1. Define Variables (Injecting paths from App State)
     ps += `# --- Configuration ---\n`;
     ps += `$ToolPath = "${toolPath}"\n`; // Quotes handle spaces
     ps += `$PaksPath = "${activeProfile.paksPath}"\n`;
     ps += `$OutputPath = "${extractOutputPath}"\n`;
     ps += `$FilterPath = "${filterPath}"\n`;

     if (activeProfile.aesKey) {
         ps += `$AesKey = "${activeProfile.aesKey}"\n`;
     } else {
         ps += `$AesKey = $null\n`;
     }

     // 2. Validation Checks
     ps += `\n# --- Validation ---\n`;
     ps += `if (-not (Test-Path $ToolPath)) {\n`;
     ps += `    Write-Error "Nástroj nebol nájdený na ceste: $ToolPath"\n`;
     ps += `    Write-Host "Prosím, skontrolujte Nastavenia v aplikácii." -ForegroundColor Yellow\n`;
     ps += `    Read-Host 'Stlačte Enter pre ukončenie...'\n    exit\n`;
     ps += `}\n`;

     // 3. Execution Command
     ps += `\n# --- Execution ---\n`;
     if (activeTool === ToolType.RETOC) {
         // Retoc Syntax: retoc to-legacy <container_path> <output_path> --filter <path> [--aes <key>]
         let cmd = `& $ToolPath to-legacy $PaksPath $OutputPath --filter $FilterPath`;
         if (activeProfile.aesKey) {
             cmd += ` --aes $AesKey`;
         }
         ps += `${cmd}\n`;
     } else {
         // Castoc Syntax
         let cmd = `& $ToolPath extract $PaksPath $OutputPath --filter $FilterPath`;
         if (activeProfile.aesKey) {
             cmd += ` --aes-key $AesKey`;
         }
         ps += `${cmd}\n`;
     }

     // 4. End State
     ps += `\nif ($LASTEXITCODE -eq 0) {\n`;
     ps += `    Write-Host "SUCCESS: Súbory boli extrahované do: $OutputPath" -ForegroundColor Green\n`;
     ps += `} else {\n`;
     ps += `    Write-Host "ERROR: Extrakcia zlyhala (Exit Code: $LASTEXITCODE)" -ForegroundColor Red\n`;
     ps += `}\n`;
     ps += `Read-Host 'Stlačte Enter pre ukončenie...'\n`;

     return { content: ps, filename: `EXTRACT_${assetName}.ps1` };
  };

  const generatePackScript = () => {
    const finalFileName = `z_${modNameStr}_SK_${modChunkId}_P.utoc`;
    const fullOutputFilePath = `${packDestFolder}\\${finalFileName}`;

    let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
    let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;

    // PowerShell Script Builder
    let ps = `# Universal UE5 Zen Tool - Packing Script\n`;
    ps += `# Generated for: ${activeProfile.name}\n\n`;

    ps += `Write-Host "Starting Packing: ${finalFileName}" -ForegroundColor Cyan\n\n`;

    // 1. Define Variables
    ps += `# --- Configuration ---\n`;
    ps += `$ToolPath = "${toolPath}"\n`;
    ps += `$SourcePath = "${modSource}"\n`;
    ps += `$OutputFile = "${fullOutputFilePath}"\n`;
    ps += `$EngineVersion = "${activeProfile.engineVersion}"\n`;

    // 2. Validation
    ps += `\n# --- Validation ---\n`;
    ps += `if (-not (Test-Path $ToolPath)) {\n`;
    ps += `    Write-Error "Nástroj nebol nájdený na ceste: $ToolPath"\n`;
    ps += `    Read-Host 'Stlačte Enter pre ukončenie...'\n    exit\n`;
    ps += `}\n`;

    // 3. Execution
    ps += `\n# --- Execution ---\n`;
    if (activeTool === ToolType.RETOC) {
        // Retoc Syntax: retoc to-zen <input_directory> <output_container> --version <ver>
        // Note: Retoc often creates .ucas automatically alongside .utoc
        ps += `& $ToolPath to-zen $SourcePath $OutputFile --version $EngineVersion\n`;
    } else {
        // Castoc Syntax
        ps += `& $ToolPath pack $SourcePath -o $OutputFile -v $EngineVersion\n`;
    }

    // 4. End State
    ps += `\nif ($LASTEXITCODE -eq 0) {\n`;
    ps += `    Write-Host "SUCCESS: Mód zabalený: $OutputFile" -ForegroundColor Green\n`;
    ps += `} else {\n`;
    ps += `    Write-Host "ERROR: Balenie zlyhalo." -ForegroundColor Red\n`;
    ps += `}\n`;
    ps += `Read-Host 'Stlačte Enter pre ukončenie...'\n`;

    return { content: ps, filename: `PACK_${modNameStr}.ps1` };
  };

  const handleDownload = (type: 'extract' | 'pack') => {
      // Validation
      if (type === 'extract') {
          if (!filterPath || !extractOutputPath) {
              onRunCommand("Chyba: Vyplňte cestu filtra a výstupný priečinok.", "Validácia");
              return;
          }
      } else {
          if (!modSource || !packDestFolder) {
              onRunCommand("Chyba: Vyplňte zdrojový a cieľový priečinok.", "Validácia");
              return;
          }
      }

      const scriptData = type === 'extract' ? generateExtractScript() : generatePackScript();

      // Download Logic
      const blob = new Blob([scriptData.content], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = scriptData.filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      onRunCommand(`Skript ${scriptData.filename} bol vygenerovaný.`, "Download");
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs for Browsing */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => handleInputFileChange(e, false)} />
      <input type="file" ref={folderInputRef} className="hidden" webkitdirectory="" directory="" onChange={(e) => handleInputFileChange(e, true)} />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Rozbalenie súborov hry (.utoc/.ucas &rarr; .uasset)</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <input
                        type="text"
                        value={filterPath}
                        onChange={(e) => setFilterPath(e.target.value)}
                        placeholder="/GameName/Content/Path/To/Asset.uasset"
                        className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                        />
                        <div className="absolute left-3 top-3 text-slate-600">/</div>
                    </div>
                    <button 
                        onClick={() => handleBrowseFile(setFilterPath)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať súbor"
                    >
                        <FileSearch size={18} />
                    </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={extractOutputPath}
                        onChange={(e) => setExtractOutputPath(e.target.value)}
                        placeholder="D:\Modding\Extracted"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                    />
                    <button 
                        onClick={() => handleBrowseFolder(setExtractOutputPath)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
                <button 
                    onClick={() => handleDownload('extract')}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
                    title="Stiahne .ps1 súbor pripravený na spustenie"
                >
                    <Download size={18} /> 
                    <span>STIAHNUŤ EXTRAKČNÝ SKRIPT</span>
                </button>
              </div>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Balenie (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Zabalenie upravených súborov do .utoc/.ucas</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              {/* Source Input */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Zdrojový priečinok módu (Source)</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={modSource}
                        onChange={(e) => setModSource(e.target.value)}
                        placeholder="F:\Preklady\Grounded 2\Export"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                    <button 
                        onClick={() => handleBrowseFolder(setModSource)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              {/* Destination Folder */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Priečinok pre export (Kde uložiť .utoc)</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={packDestFolder}
                        onChange={(e) => setPackDestFolder(e.target.value)}
                        placeholder="F:\Preklady\Grounded 2"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder(setPackDestFolder)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              {/* Naming Pattern Input */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Názov Módu (Pattern: z_Nazov_SK_ID_P)</label>
                <div className="flex items-center bg-slate-950 border border-slate-700 rounded p-1">
                    <div className="px-3 py-2 text-slate-500 font-mono select-none">z_</div>

                    <input
                        type="text"
                        value={modNameStr}
                        onChange={(e) => setModNameStr(e.target.value)}
                        placeholder="Grounded2"
                        className="flex-1 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                    />

                    <div className="px-2 py-2 text-slate-500 font-mono select-none border-l border-r border-slate-800">_SK_</div>

                    <input
                        type="text"
                        value={modChunkId}
                        onChange={(e) => setModChunkId(e.target.value)}
                        placeholder="300"
                        className="w-16 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                    />

                    <div className="px-3 py-2 text-slate-500 font-mono select-none">_P.utoc</div>
                </div>

                <div className="mt-2 text-center text-xs text-slate-500 font-mono">
                   Výstup: <span className="text-emerald-400">z_{modNameStr || 'Nazov'}_SK_{modChunkId || 'ID'}_P.utoc</span>
                </div>
              </div>

               <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500 flex justify-between items-center">
                  <span>Nástroj: <span className="text-blue-400 font-mono">{activeTool === ToolType.RETOC ? 'retoc.exe' : 'castoc.exe'}</span></span>
                  <span>Verzia: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span></span>
               </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
              <button 
                 onClick={() => handleDownload('pack')}
                 className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
                 title="Stiahne .ps1 súbor pripravený na spustenie"
              >
                <Download size={18} /> 
                <span>STIAHNUŤ BALIACI SKRIPT</span>
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GameProfile, EngineVersion } from '../types';
import { GAME_ENGINE_DB } from '../constants';
import { Save, Trash, Plus, Sparkles, FolderOpen } from 'lucide-react';

interface ProfileTabProps {
  profiles: GameProfile[];
  activeProfileId: string;
  onSelectProfile: (id: string) => void;
  onUpdateProfile: (profile: GameProfile) => void;
  onAddProfile: () => void;
  onDeleteProfile: (id: string) => void;
}

// Helper to extend HTMLInputElement attributes for React to allow webkitdirectory
declare module 'react' {
  interface InputHTMLAttributes<T> {
    webkitdirectory?: string;
    directory?: string;
  }
}

export const ProfileTab: React.FC<ProfileTabProps> = ({
  profiles,
  activeProfileId,
  onSelectProfile,
  onUpdateProfile,
  onAddProfile,
  onDeleteProfile,
}) => {
  const activeProfile = profiles.find((p) => p.id === activeProfileId);
  const [suggestion, setSuggestion] = useState<{key: string, version: EngineVersion} | null>(null);

  // File Picking Logic
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeField, setActiveField] = useState<keyof GameProfile | null>(null);

  const handleBrowse = (field: keyof GameProfile) => {
    setActiveField(field);
    if (folderInputRef.current) {
        folderInputRef.current.value = '';
        folderInputRef.current.click();
    }
  };

  const handleFolderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeField && activeProfile) {
         // @ts-ignore - file.path is available in Electron/Local context
        const path = file.path || file.name;
        // Ak browser vráti len názov súboru vo vnútri priečinka, 
        // v čistom web prostredí nevieme získať full path k priečinku bezpečnostne.
        // Ale v Electron wrapperi to funguje.

        // Pre istotu, ak je to file path, orežeme názov súboru, ak sme chceli priečinok?
        // webkitdirectory vracia zoznam súborov. file.path býva cesta k prvému súboru.
        // Orežeme názov súboru na získanie adresára.
        let dirPath = path;

        // Basic heuristic to strip filename if it looks like a file path
        if (dirPath.match(/\.[a-zA-Z0-9]+$/)) {
             const lastSlash = Math.max(dirPath.lastIndexOf('\\'), dirPath.lastIndexOf('/'));
             if (lastSlash !== -1) dirPath = dirPath.substring(0, lastSlash);
        }

        onUpdateProfile({ ...activeProfile, [activeField]: dirPath });
    }
    setActiveField(null);
  };

  // Auto-detect engine version based on name
  useEffect(() => {
    if (!activeProfile) return;

    const lowerName = activeProfile.name.toLowerCase();
    const foundKey = Object.keys(GAME_ENGINE_DB).find(key => lowerName.includes(key));

    if (foundKey) {
        setSuggestion({ key: foundKey, version: GAME_ENGINE_DB[foundKey] });
    } else {
        setSuggestion(null);
    }
  }, [activeProfile?.name]);

  const handleChange = (field: keyof GameProfile, value: string) => {
    if (activeProfile) {
      onUpdateProfile({ ...activeProfile, [field]: value });
    }
  };

  const applySuggestion = () => {
    if (suggestion && activeProfile) {
        onUpdateProfile({ ...activeProfile, engineVersion: suggestion.version });
    }
  };

  if (!activeProfile) return <div className="p-8 text-center text-slate-500">Žiadne profily neboli načítané.</div>;

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto animate-fadeIn">

      {/* Hidden Folder Input */}
      <input 
        type="file" 
        ref={folderInputRef}
        className="hidden"
        webkitdirectory="" 
        directory="" 
        onChange={handleFolderChange}
      />

      {/* Header / Selector */}
      <div className="flex items-end gap-4 border-b border-slate-800 pb-6">
        <div className="flex-1">
          <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Aktuálny Profil Hry</label>
          <div className="relative">
            <select
              value={activeProfileId}
              onChange={(e) => onSelectProfile(e.target.value)}
              className="w-full bg-slate-900 text-white border border-slate-700 rounded-lg p-3 pr-10 appearance-none focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
            >
              {profiles.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name}
                </option>
              ))}
            </select>
            <div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-400">
              <svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>
            </div>
          </div>
          <p className="text-xs text-slate-500 mt-1">Vyberte hru, ktorú chcete modovať.</p>
        </div>
        <button
          onClick={onAddProfile}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-3 rounded-lg flex items-center gap-2 font-medium transition-colors"
          title="Pridať novú hru"
        >
          <Plus size={18} /> Nová Hra
        </button>
        <button
          onClick={() => onDeleteProfile(activeProfileId)}
          className="bg-slate-800 hover:bg-red-900/50 hover:text-red-400 text-slate-400 px-4 py-3 rounded-lg flex items-center gap-2 transition-colors border border-slate-700 hover:border-red-800"
          disabled={profiles.length <= 1}
          title="Zmazať tento profil"
        >
          <Trash size={18} />
        </button>
      </div>

      {/* Form Fields */}
      <div className="grid gap-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Názov Profilu</label>
            <input
              type="text"
              value={activeProfile.name}
              onChange={(e) => handleChange('name', e.target.value)}
              placeholder="Napr. Stalker 2"
              className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Verzia Enginu (Unreal Version)</label>
            <select
              value={activeProfile.engineVersion}
              onChange={(e) => handleChange('engineVersion', e.target.value)}
              className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none"
            >
              {Object.values(EngineVersion).map((ver) => (
                <option key={ver} value={ver}>{ver}</option>
              ))}
            </select>

            {/* Auto-Suggestion Badge */}
            {suggestion && activeProfile.engineVersion !== suggestion.version && (
                <button 
                    onClick={applySuggestion}
                    className="mt-2 w-full text-left flex items-center gap-2 bg-amber-500/10 border border-amber-500/20 p-2 rounded text-xs text-amber-200 hover:bg-amber-500/20 transition-colors group"
                >
                    <Sparkles size={14} className="text-amber-400 animate-pulse" />
                    <span>
                        Rozpoznaná hra <strong>{suggestion.key}</strong>. 
                        Odporučená verzia: <span className="font-bold text-amber-400 decoration-amber-400 underline decoration-dotted">{suggestion.version}</span>
                    </span>
                    <span className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity font-bold text-amber-400">Použiť</span>
                </button>
            )}

            {!suggestion && (
                <p className="text-xs text-slate-600 mt-1">Dôležité pre správne balenie (Grounded 2 je zvyčajne 5.3 alebo 5.4).</p>
            )}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1">Koreňový Priečinok Hry (Root Path)</label>
          <div className="flex gap-2">
            <input
                type="text"
                value={activeProfile.rootPath}
                onChange={(e) => handleChange('rootPath', e.target.value)}
                className="flex-1 bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none font-mono text-sm"
                placeholder="Napr. C:\XboxGames\Grounded2"
            />
            <button 
                onClick={() => handleBrowse('rootPath')}
                className="bg-slate-800 p-2.5 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                title="Prehľadávať priečinok..."
            >
                <FolderOpen size={18} />
            </button>
          </div>
          <p className="text-xs text-slate-600 mt-1">Hlavný priečinok inštalácie hry (napr. steamapps/common/GameName).</p>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1">Priečinok s .pak súbormi (Paks Path)</label>
          <div className="flex gap-2">
            <input
                type="text"
                value={activeProfile.paksPath}
                onChange={(e) => handleChange('paksPath', e.target.value)}
                className="flex-1 bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none font-mono text-sm"
                placeholder="Napr. C:\XboxGames\Grounded2\Maine\Content\Paks"
            />
             <button 
                onClick={() => handleBrowse('paksPath')}
                className="bg-slate-800 p-2.5 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                title="Prehľadávať priečinok..."
            >
                <FolderOpen size={18} />
            </button>
          </div>
          <p className="text-xs text-slate-600 mt-1">Zvyčajne v: Game/Content/Paks. Tu program hľadá .utoc a .ucas súbory.</p>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1">AES Kľúč <span className="text-slate-600 text-xs">(Voliteľné)</span></label>
          <input
            type="text"
            value={activeProfile.aesKey}
            onChange={(e) => handleChange('aesKey', e.target.value)}
            placeholder="0x..."
            className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none font-mono text-sm"
          />
          <p className="text-xs text-slate-600 mt-1">Hexadecimálny kľúč potrebný len ak sú súbory hry šifrované.</p>
        </div>

        <div className="pt-4 flex justify-end">
           <button
            onClick={() => {/* Mock save action */}}
            className="bg-green-700 hover:bg-green-600 text-white px-6 py-2 rounded-lg flex items-center gap-2 font-medium transition-colors shadow-lg shadow-green-900/20"
          >
            <Save size={18} /> Uložiť Nastavenia Profilu
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, FileText, Download, FolderOpen, FileSearch } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
  activeTool: ToolType;
}

// Helper to extend HTMLInputElement attributes for React
declare module 'react' {
  interface InputHTMLAttributes<T> {
    webkitdirectory?: string;
    directory?: string;
  }
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand, activeTool }) => {
  // Extraction States
  const [filterPath, setFilterPath] = useState('');
  const [extractOutputPath, setExtractOutputPath] = useState('D:\\Modding\\Extracted');

  // Packing States
  const [modSource, setModSource] = useState('');
  const [packDestFolder, setPackDestFolder] = useState(''); // Kam sa uloží .utoc

  // Naming parts based on: z_Grounded2_SK_300_P
  const [modNameStr, setModNameStr] = useState('Grounded2');
  const [modChunkId, setModChunkId] = useState('300');

  // --- Path Picking Logic ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeSetter, setActiveSetter] = useState<((val: string) => void) | null>(null);

  const handleBrowseFile = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
        fileInputRef.current.click();
    }
  };

  const handleBrowseFolder = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (folderInputRef.current) {
        folderInputRef.current.value = '';
        folderInputRef.current.click();
    }
  };

  const handleInputFileChange = (e: React.ChangeEvent<HTMLInputElement>, isFolder: boolean) => {
    const file = e.target.files?.[0];
    if (file && activeSetter) {
        // @ts-ignore
        let path = file.path || file.name;

        if (isFolder) {
            // Remove filename to get dir path if we used webkitdirectory but want cleaner path
            if (path.match(/\.[a-zA-Z0-9]+$/)) {
                 const lastSlash = Math.max(path.lastIndexOf('\\'), path.lastIndexOf('/'));
                 if (lastSlash !== -1) path = path.substring(0, lastSlash);
            }
        }

        activeSetter(path);
    }
    setActiveSetter(null);
  };

  const generateExtractScript = () => {
     let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
     let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;
     const assetName = filterPath.split('/').pop()?.replace('.uasset', '') || 'Asset';

     // PowerShell Script Builder
     let ps = `# Universal UE5 Zen Tool - Extraction Script\n`;
     ps += `# Generated for: ${activeProfile.name}\n\n`;

     ps += `Write-Host "Starting Extraction for: ${assetName}" -ForegroundColor Cyan\n\n`;

     // 1. Define Variables (Injecting paths from App State)
     ps += `# --- Configuration ---\n`;
     ps += `$ToolPath = "${toolPath}"\n`; // Quotes handle spaces
     ps += `$PaksPath = "${activeProfile.paksPath}"\n`;
     ps += `$OutputPath = "${extractOutputPath}"\n`;
     ps += `$FilterPath = "${filterPath}"\n`;

     if (activeProfile.aesKey) {
         ps += `$AesKey = "${activeProfile.aesKey}"\n`;
     } else {
         ps += `$AesKey = $null\n`;
     }

     // 2. Validation Checks
     ps += `\n# --- Validation ---\n`;
     ps += `if (-not (Test-Path $ToolPath)) {\n`;
     ps += `    Write-Error "Nástroj nebol nájdený na ceste: $ToolPath"\n`;
     ps += `    Write-Host "Prosím, skontrolujte Nastavenia v aplikácii." -ForegroundColor Yellow\n`;
     ps += `    Read-Host 'Stlačte Enter pre ukončenie...'\n    exit\n`;
     ps += `}\n`;

     // 3. Execution Command
     ps += `\n# --- Execution ---\n`;
     if (activeTool === ToolType.RETOC) {
         // Retoc Syntax: retoc to-legacy <container_path> <output_path> --filter <path> [--aes <key>]
         let cmd = `& $ToolPath to-legacy $PaksPath $OutputPath --filter $FilterPath`;
         if (activeProfile.aesKey) {
             cmd += ` --aes $AesKey`;
         }
         ps += `${cmd}\n`;
     } else {
         // Castoc Syntax
         let cmd = `& $ToolPath extract $PaksPath $OutputPath --filter $FilterPath`;
         if (activeProfile.aesKey) {
             cmd += ` --aes-key $AesKey`;
         }
         ps += `${cmd}\n`;
     }

     // 4. End State
     ps += `\nif ($LASTEXITCODE -eq 0) {\n`;
     ps += `    Write-Host "SUCCESS: Súbory boli extrahované do: $OutputPath" -ForegroundColor Green\n`;
     ps += `} else {\n`;
     ps += `    Write-Host "ERROR: Extrakcia zlyhala (Exit Code: $LASTEXITCODE)" -ForegroundColor Red\n`;
     ps += `}\n`;
     ps += `Read-Host 'Stlačte Enter pre ukončenie...'\n`;

     return { content: ps, filename: `EXTRACT_${assetName}.ps1` };
  };

  const generatePackScript = () => {
    const finalFileName = `z_${modNameStr}_SK_${modChunkId}_P.utoc`;
    const fullOutputFilePath = `${packDestFolder}\\${finalFileName}`;

    let toolName = activeTool === ToolType.RETOC ? "retoc.exe" : "castoc.exe";
    let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;

    // PowerShell Script Builder
    let ps = `# Universal UE5 Zen Tool - Packing Script\n`;
    ps += `# Generated for: ${activeProfile.name}\n\n`;

    ps += `Write-Host "Starting Packing: ${finalFileName}" -ForegroundColor Cyan\n\n`;

    // 1. Define Variables
    ps += `# --- Configuration ---\n`;
    ps += `$ToolPath = "${toolPath}"\n`;
    ps += `$SourcePath = "${modSource}"\n`;
    ps += `$OutputFile = "${fullOutputFilePath}"\n`;
    ps += `$EngineVersion = "${activeProfile.engineVersion}"\n`;

    // 2. Validation
    ps += `\n# --- Validation ---\n`;
    ps += `if (-not (Test-Path $ToolPath)) {\n`;
    ps += `    Write-Error "Nástroj nebol nájdený na ceste: $ToolPath"\n`;
    ps += `    Read-Host 'Stlačte Enter pre ukončenie...'\n    exit\n`;
    ps += `}\n`;

    // 3. Execution
    ps += `\n# --- Execution ---\n`;
    if (activeTool === ToolType.RETOC) {
        // Retoc Syntax: retoc to-zen <input_directory> <output_container> --version <ver>
        // Note: Retoc often creates .ucas automatically alongside .utoc
        ps += `& $ToolPath to-zen $SourcePath $OutputFile --version $EngineVersion\n`;
    } else {
        // Castoc Syntax
        ps += `& $ToolPath pack $SourcePath -o $OutputFile -v $EngineVersion\n`;
    }

    // 4. End State
    ps += `\nif ($LASTEXITCODE -eq 0) {\n`;
    ps += `    Write-Host "SUCCESS: Mód zabalený: $OutputFile" -ForegroundColor Green\n`;
    ps += `} else {\n`;
    ps += `    Write-Host "ERROR: Balenie zlyhalo." -ForegroundColor Red\n`;
    ps += `}\n`;
    ps += `Read-Host 'Stlačte Enter pre ukončenie...'\n`;

    return { content: ps, filename: `PACK_${modNameStr}.ps1` };
  };

  const handleDownload = (type: 'extract' | 'pack') => {
      // Validation
      if (type === 'extract') {
          if (!filterPath || !extractOutputPath) {
              onRunCommand("Chyba: Vyplňte cestu filtra a výstupný priečinok.", "Validácia");
              return;
          }
      } else {
          if (!modSource || !packDestFolder) {
              onRunCommand("Chyba: Vyplňte zdrojový a cieľový priečinok.", "Validácia");
              return;
          }
      }

      const scriptData = type === 'extract' ? generateExtractScript() : generatePackScript();

      // Download Logic
      const blob = new Blob([scriptData.content], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = scriptData.filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      onRunCommand(`Skript ${scriptData.filename} bol vygenerovaný.`, "Download");
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs for Browsing */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => handleInputFileChange(e, false)} />
      <input type="file" ref={folderInputRef} className="hidden" webkitdirectory="" directory="" onChange={(e) => handleInputFileChange(e, true)} />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Section A: Extraction */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                <PackageOpen size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                <p className="text-xs text-slate-500">Rozbalenie súborov hry (.utoc/.ucas &rarr; .uasset)</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <input
                        type="text"
                        value={filterPath}
                        onChange={(e) => setFilterPath(e.target.value)}
                        placeholder="/GameName/Content/Path/To/Asset.uasset"
                        className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                        />
                        <div className="absolute left-3 top-3 text-slate-600">/</div>
                    </div>
                    <button 
                        onClick={() => handleBrowseFile(setFilterPath)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať súbor"
                    >
                        <FileSearch size={18} />
                    </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={extractOutputPath}
                        onChange={(e) => setExtractOutputPath(e.target.value)}
                        placeholder="D:\Modding\Extracted"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                    />
                    <button 
                        onClick={() => handleBrowseFolder(setExtractOutputPath)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
                <button 
                    onClick={() => handleDownload('extract')}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
                    title="Stiahne .ps1 súbor pripravený na spustenie"
                >
                    <Download size={18} /> 
                    <span>STIAHNUŤ EXTRAKČNÝ SKRIPT</span>
                </button>
              </div>
            </div>
          </div>

          {/* Section B: Packing */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
            <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
              <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                <Box size={24} />
              </div>
              <div>
                <h3 className="font-bold text-slate-200">Balenie (Legacy &rarr; Zen)</h3>
                <p className="text-xs text-slate-500">Zabalenie upravených súborov do .utoc/.ucas</p>
              </div>
            </div>

            <div className="p-6 space-y-6 flex-1">
              {/* Source Input */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Zdrojový priečinok módu (Source)</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={modSource}
                        onChange={(e) => setModSource(e.target.value)}
                        placeholder="F:\Preklady\Grounded 2\Export"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                    <button 
                        onClick={() => handleBrowseFolder(setModSource)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              {/* Destination Folder */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Priečinok pre export (Kde uložiť .utoc)</label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={packDestFolder}
                        onChange={(e) => setPackDestFolder(e.target.value)}
                        placeholder="F:\Preklady\Grounded 2"
                        className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                    />
                     <button 
                        onClick={() => handleBrowseFolder(setPackDestFolder)}
                        className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                        title="Vybrať priečinok"
                    >
                        <FolderOpen size={18} />
                    </button>
                </div>
              </div>

              {/* Naming Pattern Input */}
              <div>
                <label className="block text-sm font-medium text-slate-400 mb-2">Názov Módu (Pattern: z_Nazov_SK_ID_P)</label>
                <div className="flex items-center bg-slate-950 border border-slate-700 rounded p-1">
                    <div className="px-3 py-2 text-slate-500 font-mono select-none">z_</div>

                    <input
                        type="text"
                        value={modNameStr}
                        onChange={(e) => setModNameStr(e.target.value)}
                        placeholder="Grounded2"
                        className="flex-1 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                    />

                    <div className="px-2 py-2 text-slate-500 font-mono select-none border-l border-r border-slate-800">_SK_</div>

                    <input
                        type="text"
                        value={modChunkId}
                        onChange={(e) => setModChunkId(e.target.value)}
                        placeholder="300"
                        className="w-16 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                    />

                    <div className="px-3 py-2 text-slate-500 font-mono select-none">_P.utoc</div>
                </div>

                <div className="mt-2 text-center text-xs text-slate-500 font-mono">
                   Výstup: <span className="text-emerald-400">z_{modNameStr || 'Nazov'}_SK_{modChunkId || 'ID'}_P.utoc</span>
                </div>
              </div>

               <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500 flex justify-between items-center">
                  <span>Nástroj: <span className="text-blue-400 font-mono">{activeTool === ToolType.RETOC ? 'retoc.exe' : 'castoc.exe'}</span></span>
                  <span>Verzia: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span></span>
               </div>
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
              <button 
                 onClick={() => handleDownload('pack')}
                 className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
                 title="Stiahne .ps1 súbor pripravený na spustenie"
              >
                <Download size={18} /> 
                <span>STIAHNUŤ BALIACI SKRIPT</span>
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { GameProfile, ToolType, AppSettings } from '../types';
import { PackageOpen, Box, FileText, Copy, Check, FolderOpen, FileSearch, Terminal } from 'lucide-react';

interface OperationsTabProps {
  activeProfile: GameProfile;
  settings: AppSettings;
  onRunCommand: (command: string, description: string) => void;
  activeTool: ToolType;
}

// Helper to extend HTMLInputElement attributes for React
declare module 'react' {
  interface InputHTMLAttributes<T> {
    webkitdirectory?: string;
    directory?: string;
  }
}

export const OperationsTab: React.FC<OperationsTabProps> = ({ activeProfile, settings, onRunCommand, activeTool }) => {
  // Extraction States
  const [filterPath, setFilterPath] = useState('');
  const [extractOutputPath, setExtractOutputPath] = useState('D:\\Modding\\Extracted');

  // Packing States
  const [modSource, setModSource] = useState('');
  const [packDestFolder, setPackDestFolder] = useState(''); // Kam sa uloží .utoc

  // Naming parts based on: z_Grounded2_SK_300_P
  const [modNameStr, setModNameStr] = useState('Grounded2');
  const [modChunkId, setModChunkId] = useState('300');

  // Command Output State
  const [generatedCommand, setGeneratedCommand] = useState('');
  const [copied, setCopied] = useState(false);

  // --- Path Picking Logic ---
  const fileInputRef = useRef<HTMLInputElement>(null);
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeSetter, setActiveSetter] = useState<((val: string) => void) | null>(null);

  const handleBrowseFile = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
        fileInputRef.current.click();
    }
  };

  const handleBrowseFolder = (setter: (val: string) => void) => {
    setActiveSetter(() => setter);
    if (folderInputRef.current) {
        folderInputRef.current.value = '';
        folderInputRef.current.click();
    }
  };

  const handleInputFileChange = (e: React.ChangeEvent<HTMLInputElement>, isFolder: boolean) => {
    const file = e.target.files?.[0];
    if (file && activeSetter) {
        // @ts-ignore
        let path = file.path || file.name;

        if (isFolder) {
            // Remove filename to get dir path if we used webkitdirectory but want cleaner path
            if (path.match(/\.[a-zA-Z0-9]+$/)) {
                 const lastSlash = Math.max(path.lastIndexOf('\\'), path.lastIndexOf('/'));
                 if (lastSlash !== -1) path = path.substring(0, lastSlash);
            }
        }

        activeSetter(path);
    }
    setActiveSetter(null);
  };

  const handleGenerateCommand = (type: 'extract' | 'pack') => {
      let cmd = "";
      let toolPath = activeTool === ToolType.RETOC ? settings.retocPath : settings.castocPath;

      // Basic validation
      if (!toolPath) toolPath = "retoc.exe";

      if (type === 'extract') {
          if (!filterPath || !extractOutputPath) {
              onRunCommand("Chyba: Vyplňte cestu filtra a výstupný priečinok.", "Validácia");
              return;
          }

          // Syntax: & "Path\To\Tool.exe" to-legacy "PaksPath" "OutputPath" --filter "FilterPath"
          if (activeTool === ToolType.RETOC) {
              cmd = `& "${toolPath}" to-legacy "${activeProfile.paksPath}" "${extractOutputPath}" --filter "${filterPath}"`;
              if (activeProfile.aesKey) {
                  cmd += ` --aes "${activeProfile.aesKey}"`;
              }
          } else {
              // Castoc fallback
              cmd = `& "${toolPath}" extract "${activeProfile.paksPath}" "${extractOutputPath}" --filter "${filterPath}"`;
              if (activeProfile.aesKey) {
                  cmd += ` --aes-key "${activeProfile.aesKey}"`;
              }
          }

      } else {
          // PACKING
          if (!modSource || !packDestFolder) {
              onRunCommand("Chyba: Vyplňte zdrojový a cieľový priečinok.", "Validácia");
              return;
          }

          const finalFileName = `z_${modNameStr}_SK_${modChunkId}_P.utoc`;
          const fullOutputFilePath = `${packDestFolder}\\${finalFileName}`;

          // Syntax: & "Path\To\Tool.exe" to-zen --version UE5_X "SourcePath" "OutputFile"
          if (activeTool === ToolType.RETOC) {
              cmd = `& "${toolPath}" to-zen --version ${activeProfile.engineVersion} "${modSource}" "${fullOutputFilePath}"`;
          } else {
              // Castoc fallback
              cmd = `& "${toolPath}" pack "${modSource}" -o "${fullOutputFilePath}" -v ${activeProfile.engineVersion}`;
          }
      }

      setGeneratedCommand(cmd);
      setCopied(false);
      onRunCommand(cmd, "Vygenerovaný príkaz");
  };

  const copyToClipboard = () => {
      navigator.clipboard.writeText(generatedCommand);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex flex-col h-full animate-fadeIn">
      {/* Hidden Inputs for Browsing */}
      <input type="file" ref={fileInputRef} className="hidden" onChange={(e) => handleInputFileChange(e, false)} />
      <input type="file" ref={folderInputRef} className="hidden" webkitdirectory="" directory="" onChange={(e) => handleInputFileChange(e, true)} />

      <div className="flex-1 overflow-y-auto p-6">
        <div className="max-w-5xl mx-auto space-y-8">

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Section A: Extraction */}
            <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
                <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
                <div className="bg-amber-500/10 p-2 rounded-lg text-amber-500">
                    <PackageOpen size={24} />
                </div>
                <div>
                    <h3 className="font-bold text-slate-200">Extrakcia (Zen &rarr; Legacy)</h3>
                    <p className="text-xs text-slate-500">Rozbalenie súborov hry (.utoc/.ucas &rarr; .uasset)</p>
                </div>
                </div>

                <div className="p-6 space-y-6 flex-1">
                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Cesta Filtra (Konkrétny súbor .uasset)</label>
                    <div className="flex gap-2">
                        <div className="relative flex-1">
                            <input
                            type="text"
                            value={filterPath}
                            onChange={(e) => setFilterPath(e.target.value)}
                            placeholder="/GameName/Content/Path/To/Asset.uasset"
                            className="w-full bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm pl-8 transition-colors"
                            />
                            <div className="absolute left-3 top-3 text-slate-600">/</div>
                        </div>
                        <button 
                            onClick={() => handleBrowseFile(setFilterPath)}
                            className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                            title="Vybrať súbor"
                        >
                            <FileSearch size={18} />
                        </button>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Výstupný priečinok extrakcie</label>
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={extractOutputPath}
                            onChange={(e) => setExtractOutputPath(e.target.value)}
                            placeholder="D:\Modding\Extracted"
                            className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-amber-500 outline-none font-mono text-sm transition-colors"
                        />
                        <button 
                            onClick={() => handleBrowseFolder(setExtractOutputPath)}
                            className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                            title="Vybrať priečinok"
                        >
                            <FolderOpen size={18} />
                        </button>
                    </div>
                </div>

                <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
                    <button 
                        onClick={() => handleGenerateCommand('extract')}
                        className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-amber-900/20 active:scale-[0.98]"
                    >
                        <FileText size={18} /> 
                        <span>GENEROVAŤ PRÍKAZ</span>
                    </button>
                </div>
                </div>
            </div>

            {/* Section B: Packing */}
            <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden flex flex-col shadow-xl">
                <div className="bg-slate-850 p-4 border-b border-slate-800 flex items-center gap-3">
                <div className="bg-emerald-500/10 p-2 rounded-lg text-emerald-500">
                    <Box size={24} />
                </div>
                <div>
                    <h3 className="font-bold text-slate-200">Balenie (Legacy &rarr; Zen)</h3>
                    <p className="text-xs text-slate-500">Zabalenie upravených súborov do .utoc/.ucas</p>
                </div>
                </div>

                <div className="p-6 space-y-6 flex-1">
                {/* Source Input */}
                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Zdrojový priečinok módu (Source)</label>
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={modSource}
                            onChange={(e) => setModSource(e.target.value)}
                            placeholder="F:\Preklady\Grounded 2\Export"
                            className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                        />
                        <button 
                            onClick={() => handleBrowseFolder(setModSource)}
                            className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                            title="Vybrať priečinok"
                        >
                            <FolderOpen size={18} />
                        </button>
                    </div>
                </div>

                {/* Destination Folder */}
                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Priečinok pre export (Kde uložiť .utoc)</label>
                    <div className="flex gap-2">
                        <input
                            type="text"
                            value={packDestFolder}
                            onChange={(e) => setPackDestFolder(e.target.value)}
                            placeholder="F:\Preklady\Grounded 2"
                            className="flex-1 bg-slate-950 border border-slate-700 rounded p-3 text-slate-200 focus:border-emerald-500 outline-none font-mono text-sm transition-colors"
                        />
                        <button 
                            onClick={() => handleBrowseFolder(setPackDestFolder)}
                            className="bg-slate-800 p-3 rounded border border-slate-700 hover:bg-slate-700 text-slate-400 hover:text-white transition-colors"
                            title="Vybrať priečinok"
                        >
                            <FolderOpen size={18} />
                        </button>
                    </div>
                </div>

                {/* Naming Pattern Input */}
                <div>
                    <label className="block text-sm font-medium text-slate-400 mb-2">Názov Módu (Pattern: z_Nazov_SK_ID_P)</label>
                    <div className="flex items-center bg-slate-950 border border-slate-700 rounded p-1">
                        <div className="px-3 py-2 text-slate-500 font-mono select-none">z_</div>

                        <input
                            type="text"
                            value={modNameStr}
                            onChange={(e) => setModNameStr(e.target.value)}
                            placeholder="Grounded2"
                            className="flex-1 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                        />

                        <div className="px-2 py-2 text-slate-500 font-mono select-none border-l border-r border-slate-800">_SK_</div>

                        <input
                            type="text"
                            value={modChunkId}
                            onChange={(e) => setModChunkId(e.target.value)}
                            placeholder="300"
                            className="w-16 bg-transparent text-center text-slate-200 outline-none font-mono font-bold placeholder-slate-700"
                        />

                        <div className="px-3 py-2 text-slate-500 font-mono select-none">_P.utoc</div>
                    </div>
                </div>

                <div className="bg-slate-950/50 p-3 rounded border border-slate-800 text-xs text-slate-500 flex justify-between items-center">
                    <span>Nástroj: <span className="text-blue-400 font-mono">{activeTool === ToolType.RETOC ? 'retoc.exe' : 'castoc.exe'}</span></span>
                    <span>Verzia: <span className="text-emerald-400 font-bold">{activeProfile.engineVersion}</span></span>
                </div>

                <div className="p-4 bg-slate-950/50 border-t border-slate-800 mt-auto">
                    <button 
                        onClick={() => handleGenerateCommand('pack')}
                        className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-[0.98]"
                    >
                        <FileText size={18} /> 
                        <span>GENEROVAŤ PRÍKAZ</span>
                    </button>
                </div>
                </div>
            </div>
          </div>

          {/* Generated Command Output Area */}
          {generatedCommand && (
              <div className="bg-black/40 border border-slate-700 rounded-xl p-4 animate-fadeIn">
                  <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-2 text-slate-400">
                          <Terminal size={16} />
                          <span className="text-sm font-bold uppercase tracking-wider">Vygenerovaný Príkaz</span>
                      </div>
                      <button 
                          onClick={copyToClipboard}
                          className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm font-bold transition-all ${copied ? 'bg-green-600 text-white' : 'bg-slate-700 hover:bg-slate-600 text-slate-200'}`}
                      >
                          {copied ? <Check size={14} /> : <Copy size={14} />}
                          {copied ? 'SKOPIROVANÉ' : 'KOPIROVAŤ'}
                      </button>
                  </div>
                  <div className="relative">
                      <textarea 
                          readOnly
                          value={generatedCommand}
                          className="w-full h-24 bg-slate-950 text-emerald-400 font-mono text-sm p-4 rounded-lg border border-slate-800 outline-none resize-none shadow-inner"
                      />
                  </div>
                  <p className="text-xs text-slate-500 mt-2 text-center">
                      Skopírujte tento príkaz a vložte ho do PowerShell okna (Admin).
                  </p>
              </div>
          )}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { GameProfile, EngineVersion } from '../types';
import { GAME_ENGINE_DB } from '../constants';
import { Save, Trash, Plus, Sparkles, FolderOpen } from 'lucide-react';

interface ProfileTabProps {
  profiles: GameProfile[];
  activeProfileId: string;
  onSelectProfile: (id: string) => void;
  onUpdateProfile: (profile: GameProfile) => void;
  onAddProfile: () => void;
  onDeleteProfile: (id: string) => void;
}

export const ProfileTab: React.FC<ProfileTabProps> = ({
  profiles,
  activeProfileId,
  onSelectProfile,
  onUpdateProfile,
  onAddProfile,
  onDeleteProfile,
}) => {
  const activeProfile = profiles.find((p) => p.id === activeProfileId);
  const [suggestion, setSuggestion] = useState<{key: string, version: EngineVersion} | null>(null);

  // File Picking Logic
  const folderInputRef = useRef<HTMLInputElement>(null);
  const [activeField, setActiveField] = useState<keyof GameProfile | null>(null);

  const handleBrowse = (field: keyof GameProfile) => {
    setActiveField(field);
    if (folderInputRef.current) {
        folderInputRef.current.value = '';
        folderInputRef.current.click();
    }
  };

  const handleFolderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeField && activeProfile) {
         // @ts-ignore - file.path is available in Electron/Local context
        const path = file.path || file.name;
        // Ak browser vráti len názov súboru vo vnútri priečinka, 
        // v čistom web prostredí nevieme získať full path k priečinku bezpečnostne.
        // Ale v Electron wrapperi to funguje.

        // Pre istotu, ak je to file path, orežeme názov súboru, ak sme chceli priečinok?
        // webkitdirectory vracia zoznam súborov. file.path býva cesta k prvému súboru.
        // Orežeme názov súboru na získanie adresára.
        let dirPath = path;

        // Basic heuristic to strip filename if it looks like a file path
        if (dirPath.match(/\.[a-zA-Z0-9]+$/)) {
             const lastSlash = Math.max(dirPath.lastIndexOf('\\'), dirPath.lastIndexOf('/'));
             if (lastSlash !== -1) dirPath = dirPath.substring(0, lastSlash);
        }

        onUpdateProfile({ ...activeProfile, [activeField]: dirPath });
    }
    setActiveField(null);
  };

  // Auto-detect engine version based on name
  useEffect(() => {
    if (!activeProfile) return;

    const lowerName = activeProfile.name.toLowerCase();
    const foundKey = Object.keys(GAME_ENGINE_DB).find(key => lowerName.includes(key));

    if (foundKey) {
        setSuggestion({ key: foundKey, version: GAME_ENGINE_DB[foundKey] });
    } else {
        setSuggestion(null);
    }
  }, [activeProfile?.name]);

  const handleChange = (field: keyof GameProfile, value: string) => {
    if (activeProfile) {
      onUpdateProfile({ ...activeProfile, [field]: value });
    }
  };

  const applySuggestion = () => {
    if (suggestion && activeProfile) {
        onUpdateProfile({ ...activeProfile, engineVersion: suggestion.version });
    }
  };

  if (!activeProfile) return <div className="p-8 text-center text-slate-500">Žiadne profily neboli načítané.</div>;

  return (
    <div className="p-6 space-y-6 max-w-4xl mx-auto animate-fadeIn">

      {/* Hidden Folder Input */}
      <input 
        type="file" 
        ref={folderInputRef}
        className="hidden"
        // Use spread with any cast to avoid module augmentation issues for non-standard attributes
        {...({ webkitdirectory: "", directory: "" } as any)}
        onChange={handleFolderChange}
      />

      {/* Header / Selector */}
      <div className="flex items-end gap-4 border-b border-slate-800 pb-6">
        <div className="flex-1">
          <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Aktuálny Profil Hry</label>
          <div className="relative">
            <select
              value={activeProfileId}
              onChange={(e) => onSelectProfile(e.target.value)}
              className="w-full bg-slate-900 text-white border border-slate-700 rounded-lg p-3 pr-10 appearance-none focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
            >
              {profiles.map((p) => (
                <option key={p.id} value={p.id}>
                  {p.name}
                </option>
              ))}
            </select>
            <div className="absolute inset-y-0 right-0 flex items-center px-3 pointer-events-none text-slate-400">
              <svg className="w-4 h-4 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>
            </div>
          </div>
          <p className="text-xs text-slate-500 mt-1">Vyberte hru, ktorú chcete modovať.</p>
        </div>
        <button
          onClick={onAddProfile}
          className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-3 rounded-lg flex items-center gap-2 font-medium transition-colors"
          title="Pridať novú hru"
        >
          <Plus size={18} /> Nová Hra
        </button>
        <button
          onClick={() => onDeleteProfile(activeProfileId)}
          className="bg-slate-800 hover:bg-red-900/50 hover:text-red-400 text-slate-400 px-4 py-3 rounded-lg flex items-center gap-2 transition-colors border border-slate-700 hover:border-red-800"
          disabled={profiles.length <= 1}
          title="Zmazať tento profil"
        >
          <Trash size={18} />
        </button>
      </div>

      {/* Form Fields */}
      <div className="grid gap-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Názov Profilu</label>
            <input
              type="text"
              value={activeProfile.name}
              onChange={(e) => handleChange('name', e.target.value)}
              placeholder="Napr. Stalker 2"
              className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-400 mb-1">Verzia Enginu (Unreal Version)</label>
            <select
              value={activeProfile.engineVersion}
              onChange={(e) => handleChange('engineVersion', e.target.value)}
              className="w-full bg-slate-950 border border-slate-700 rounded p-2.5 text-slate-200 focus:border-blue-500 outline-none"
            >
              {Object.values(EngineVersion).map((ver) => (
                <option key={ver} value={ver}>{ver}</option>
              ))}
            </select>

            {/* Auto-Suggestion Badge */}
            {suggestion && activeProfile.engineVersion !== suggestion.version && (
                <button 
                    onClick={applySuggestion}
                    className="mt-2 w-full text-left flex items-center gap-2 bg-amber-500/10 border border-amber-500/20 p-2 rounded text-xs text-amber-200 hover:bg-amber-500/20 transition-colors group"
                >
                    <Sparkles size={14} className="text-amber-400 animate-pulse" />
                    <span>
                        Rozpoznaná hra <strong>{suggestion.key}</strong>. 
                        Odporučená verzia: <span className="font-bold text-amber-400 decoration-amber-400 underline decoration-dotted">{suggestion.version}</span>
                    </span>
                    <span className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity font-bold text-amber-400">Použiť</span>
                </button>
            )}

            {!suggestion && (
                <p className="text-xs text-slate-600 mt-1">Dôležité pre správne balenie (Grounded 2 je zvyčajne 5.3 alebo 5.4).</p>
            )}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-400 mb-1">Koreňový Priečinok Hry (Root Path)</label>
          <div className="flex gap-2">
            <input
                type="text"
                value={activeProfile.rootPath}
                onChange={(e) => handleChange('rootPath', e.target.value)}
